import React, { useState, useEffect } from "react";

const DesignerForm = ({ onSubmit, initialData }) => {
  const [formData, setFormData] = useState({
    name: "",
    email: "",
    type: "",
    previousDesigns: ""
  });

  // Load existing data when editing
  useEffect(() => {
    if (initialData) {
      setFormData({
        ...initialData,
        previousDesigns: Array.isArray(initialData.previousDesigns)
          ? initialData.previousDesigns.join(", ")
          : initialData.previousDesigns || ""
      });
    }
  }, [initialData]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  };

  const handleSubmit = (e) => {
    e.preventDefault();

    let previousDesigns = formData.previousDesigns;
    if (typeof previousDesigns === "string") {
      previousDesigns = previousDesigns
        .split(",")
        .map((d) => d.trim())
        .filter((d) => d.length > 0);
    }

    const designerData = {
      ...formData,
      previousDesigns
    };

    onSubmit(designerData);
    setFormData({ name: "", email: "", type: "", previousDesigns: "" }); // reset form
  };

  return (
    <div className="form-container">
      <h2>{initialData ? "Update Designer" : "Add Designer"}</h2>
      <form onSubmit={handleSubmit}>
        <div className="form-group">
          <label>Designer Name:</label>
          <input
            type="text"
            name="name"
            placeholder="Enter designer name"
            value={formData.name}
            onChange={handleChange}
            required
          />
        </div>

        <div className="form-group">
          <label>Email Address:</label>
          <input
            type="email"
            name="email"
            placeholder="Enter designer email"
            value={formData.email}
            onChange={handleChange}
            required
          />
        </div>

        <div className="form-group">
          <label>Designer Type:</label>
          <select
            name="type"
            value={formData.type}
            onChange={handleChange}
            required
          >
            <option value="">-- Select Type --</option>
            <option value="fashion">Fashion</option>
            <option value="graphic">Graphic</option>
            <option value="interior">Interior</option>
          </select>
        </div>

        <div className="form-group">
          <label>Previous Designs:</label>
          <input
            type="text"
            name="previousDesigns"
            placeholder="e.g. logo1, poster2, catalog3"
            value={formData.previousDesigns}
            onChange={handleChange}
          />
          <small>Enter comma-separated values</small>
        </div>

        <button type="submit" className="btn-submit">
          {initialData ? "Update Designer" : "Add Designer"}
        </button>
      </form>
    </div>
  );
};

export default DesignerForm;
